    ap = argparse.ArgumentParser()
    ap.add_argument("--host", default="0.0.0.0")
    ap.add_argument("--port", type=int, default=7777)
    ap.add_argument("--tick-hz", type=int, default=30)
    ap.add_argument("--snapshot-hz", type=int, default=20)
    ap.add_argument("--max-players", type=int, default=200)
    ap.add_argument("--idle-timeout", type=int, default=30)
    ap.add_argument("--ping-interval", type=int, default=5)
    ap.add_argument("--max-speed", type=float, default=20.0)
    return ap.parse_args()


